The `debounce` function prevents a given function from being called too many times in a short period of time by introducing a delay between calls.

```javascript
function debounce(waitTime) {
  let timeout;

  return function (fn, ...args) {
    if (timeout) clearTimeout(timeout);
    timeout = setTimeout(() => {
      fn(...args);
    }, waitTime);
  };
}

const debouncedLog = debounce(1000);

// Call debouncedLog multiple times in quick succession
debouncedLog(console.log, 'Hello');
debouncedLog(console.log, 'World'); // This log will be debounced
setTimeout(() => debouncedLog(console.log, 'Delayed'), 1500); // This log will be called 1.5 seconds after the previous call
```
